# WRONG — fragile string parsing between stages
def stage_a(text: str) -> str:
    return call_llm(f"Extract entities from: {text}")

def stage_b(stage_a_output: str) -> str:
    # Brittle: breaks if LLM outputs "Entity: X" instead of "ENTITY: X"
    entities = [line.split(": ")[1] for line in stage_a_output.split("\n") if ":" in line]
    return summarise(entities)

# CORRECT — typed contract
class EntityList(BaseModel):
    entities: list[str]

def stage_a(text: str) -> EntityList:
    raw = call_llm_structured(f"Extract entities. Return JSON {{entities: [...]}} from: {text}")
    return EntityList.model_validate_json(raw)  # raises on malformed output

def stage_b(inp: EntityList) -> str:
    return summarise(inp.entities)  # never parses a string
